import json
import pymysql
import os

def lambda_handler(event, context):
    # Database connection parameters
    db_host = os.environ['DB_HOST']
    db_user = os.environ['DB_USER']
    db_password = os.environ['DB_PASSWORD']
    db_name = os.environ['DB_NAME']

    # Extract search parameters from the event
    search_params = event.get('queryStringParameters', {})
    
    # Establish a database connection
    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        cursorclass=pymysql.cursors.DictCursor
    )
    
    try:
        with connection.cursor() as cursor:
            # Base query
            query = "SELECT * FROM products WHERE 1=1"
            query_params = []

            # Dynamically build the query based on search parameters
            if 'name' in search_params:
                query += " AND name LIKE %s"
                query_params.append(f"%{search_params['name']}%")
            if 'category' in search_params:
                query += " AND category = %s"
                query_params.append(search_params['category'])
            if 'min_price' in search_params:
                query += " AND price >= %s"
                query_params.append(float(search_params['min_price']))
            if 'max_price' in search_params:
                query += " AND price <= %s"
                query_params.append(float(search_params['max_price']))

            # Execute the query securely
            cursor.execute(query, query_params)
            results = cursor.fetchall()

        # Return the results as a JSON response
        return {
            'statusCode': 200,
            'body': json.dumps(results)
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }

    finally:
        connection.close()